import { useEffect, useState } from "react";
import axios from "axios";

interface User {
  handle: string;
  rating: number;
  rank: string;
}

export default function ClassLeaderboard() {
  const [classId, setClassId] = useState("");
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchLeaderboard = () => {
    if (!classId) return;

    setLoading(true);
    axios
      .get(`http://localhost:5000/leaderboard/class/${classId}`)
      .then((res) => {
        setUsers(res.data);
        setLoading(false);
      });
  };

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-6">
      <h2 className="text-2xl font-bold">Class Leaderboard</h2>

      {/* Input */}
      <div className="flex gap-3">
        <input
          className="flex-1 border rounded px-3 py-2"
          placeholder="Enter class name (e.g. CS-A)"
          value={classId}
          onChange={(e) => setClassId(e.target.value)}
        />
        <button
          onClick={fetchLeaderboard}
          className="px-4 py-2 bg-indigo-600 text-white rounded"
        >
          View
        </button>
      </div>

      {/* Leaderboard */}
      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="bg-white dark:bg-gray-800 rounded-xl shadow">
          {users.map((u, i) => (
            <div
              key={u.handle}
              className="flex justify-between px-4 py-3 border-b dark:border-gray-700"
            >
              <span>
                #{i + 1} {u.handle}
              </span>
              <span>{u.rating}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
